8730	[Ext-vanishing forces the coyoneda right-derived object to vanish]
8731	  \label{lem:isZero_coyoneda_rightDerived_of_forall_ext_eq_zero}
8732	  \lean{AlgebraicGeometry.isZero_coyoneda_rightDerived_of_forall_ext_eq_zero,
8733	    AlgebraicGeometry.preadditiveCoyoneda_mapHomologicalComplex_d_apply}
8734	  \uses{lem:ext_homcomplex_mathlib, lem:right_derived_injective_resolution}
8735	  Let \(\mathcal{C}\) be an abelian category with enough injectives, let \(P, H \in \mathcal{C}\), and
8736	  let \(q \geq 1\). If every class \(e \in \operatorname{Ext}^q(P, H)\) is zero, then the right-derived
8737	  object of the covariant hom-functor vanishes at \(H\):
8738	  \[
8739	    \bigl((\operatorname{Hom}(P, -)).\mathrm{rightDerived}\,q\bigr)(H) \;\text{ is a zero object.}
8740	  \]
8741	\end{lemma}
8742	\begin{proof}
8743	  \uses{lem:ext_homcomplex_mathlib, lem:right_derived_injective_resolution}
8744	  Choose an injective resolution \(H \to \mathcal{I}^\bullet\). By the right-derived-object comparison
8745	  (Lemma~\ref{lem:right_derived_injective_resolution}) the value
8746	  \(((\operatorname{Hom}(P,-)).\mathrm{rightDerived}\,q)(H)\) is identified with the degree-\(q\)
8747	  homology of the \(\operatorname{Hom}\)-cochain complex \(n \mapsto (P \to \mathcal{I}^n)\), whose
8748	  differential is post-composition with the differential of \(\mathcal{I}^\bullet\). A degree-\(q\)
8749	  cocycle is a map \(f : P \to \mathcal{I}^q\) with \(f \circ d = 0\), and by the
8750	  Ext--Hom-complex identification (Lemma~\ref{lem:ext_homcomplex_mathlib}) such an \(f\) is a
8751	  coboundary exactly when its class \(\operatorname{extMk} f \in \operatorname{Ext}^q(P, H)\) vanishes.
8752	  The hypothesis makes every such class zero, so every \(q\)-cocycle is a coboundary; the homology at
8753	  \(q\) is therefore zero and the right-derived object is a zero object.
8754	\end{proof}
