8759	[An isomorphism in the first Ext-argument transfers subsingletons]
8760	  \label{lem:subsingleton_ext_of_iso_fst}
8761	  \lean{AlgebraicGeometry.subsingleton_ext_of_iso_fst}
8762	  \uses{lem:ext_homcomplex_mathlib}
8763	  Let \(\mathcal{C}\) be an abelian category with an Ext-theory, \(\varphi : A \cong B\) an
8764	  isomorphism, \(Y \in \mathcal{C}\) an object and \(q\) a degree. If \(\operatorname{Ext}^q(B, Y)\)
8765	  is a subsingleton (has at most one element), then so is \(\operatorname{Ext}^q(A, Y)\).
8766	\end{lemma}
8767	\begin{proof}
8768	  \uses{lem:ext_homcomplex_mathlib}
8769	  Ext is contravariant in its first argument. For any \(z \in \operatorname{Ext}^q(A, Y)\),
8770	  associativity of Yoneda composition with the degree-\(0\) classes of \(\varphi\) gives
8771	  \[
8772	    z = \operatorname{mk}_0(\varphi.\mathrm{hom}) \circ \bigl(\operatorname{mk}_0(\varphi.\mathrm{inv})
8773	      \circ z\bigr),
8774	  \]
8775	  using \(\varphi.\mathrm{inv} \circ \varphi.\mathrm{hom} = \mathrm{id}\) and the identity law
8776	  \(\operatorname{mk}_0(\mathrm{id}) \circ z = z\). The inner factor
8777	  \(\operatorname{mk}_0(\varphi.\mathrm{inv}) \circ z\) lives in the subsingleton
8778	  \(\operatorname{Ext}^q(B, Y)\), hence equals \(0\); composing with \(0\) gives \(z = 0\). Since every
8779	  element is \(0\), \(\operatorname{Ext}^q(A, Y)\) is a subsingleton.
8780	\end{proof}
